let DB = {
  listings: [],
  users: [],
  reports: [],
  wishlist: []
};

// Initialize DB from LocalStorage if available
function initDB() {
  const savedListings = localStorage.getItem('bubu_listings');
  DB.listings = savedListings ? JSON.parse(savedListings) : [];

  const savedWishlist = localStorage.getItem('bubu_wishlist');
  DB.wishlist = savedWishlist ? JSON.parse(savedWishlist) : [];

  const savedUsers = localStorage.getItem('bubu_users');
  DB.users = savedUsers ? JSON.parse(savedUsers) : [];
}

function saveWishlist() {
  localStorage.setItem('bubu_wishlist', JSON.stringify(DB.wishlist));
}


function saveListings() {
  localStorage.setItem('bubu_listings', JSON.stringify(DB.listings));
}

/* ============================================================
   APP STATE
============================================================ */
const state = {
  currentPage: 'home',
  currentListing: null,
  searchQuery: '',
  searchFilters: { category: '', condition: '', priceMin: '', priceMax: '', brand: '', bodyType: '', storage: '', ram: '', priceRange: '', subCategory: '' },
  sortMode: { featured: 'newest', recent: 'newest', search: 'newest' },
  currentUser: null, // Starts as null for mandatory login
  deleteTarget: null,
  typingTimeout: null,
  sliderIndex: 0,
  sliderTimer: null
};

/* ============================================================
   FEATURED SLIDER LOGIC
============================================================ */
function initSlider(featured) {
  const container = document.getElementById('sliderContainer');
  const dots = document.getElementById('sliderDots');
  if (!container || !dots) return;

  if (featured.length === 0) {
    container.innerHTML = `<div class="slide"><p style="color:var(--text-secondary)">No ads available</p></div>`;
    return;
  }

  container.innerHTML = featured.map(l => `
    <div class="slide">
      ${renderListingCard(l)}
    </div>
  `).join('');

  const totalSlides = container.children.length;
  dots.innerHTML = Array.from({ length: totalSlides }).map((_, i) => `
    <div class="dot ${i === 0 ? 'active' : ''}" onclick="goToSlide(${i})"></div>
  `).join('');

  state.sliderIndex = 0;
  startAutoSlide();
}

function moveSlider(dir) {
  const container = document.getElementById('sliderContainer');
  if (!container) return;
  const slides = container.children.length;
  if (slides <= 1) return;

  state.sliderIndex = (state.sliderIndex + dir + slides) % slides;
  updateSlider();
  startAutoSlide(); // Reset timer with correct context
}

function goToSlide(index) {
  state.sliderIndex = index;
  updateSlider();
  startAutoSlide();
}

function updateSlider() {
  const container = document.getElementById('sliderContainer');
  const dots = document.querySelectorAll('.dot');
  if (!container) return;

  container.style.transform = `translateX(-${state.sliderIndex * 100}%)`;

  dots.forEach((dot, i) => {
    dot.classList.toggle('active', i === state.sliderIndex);
  });
}

function startAutoSlide() {
  if (state.sliderTimer) clearInterval(state.sliderTimer);

  // Custom timing: 2s if on Logo (index 0), 5s otherwise
  const delay = state.sliderIndex === 0 ? 2000 : 5000;

  state.sliderTimer = setInterval(() => {
    moveSlider(1);
  }, delay);
}

/* ============================================================
   NAVIGATION & MENU
============================================================ */
function toggleSideMenu() {
  const menu = document.getElementById('sideMenu');
  const overlay = document.getElementById('sideMenuOverlay');
  if (!menu || !overlay) return;

  menu.classList.toggle('active');
  overlay.classList.toggle('active');

  // Prevent scrolling when menu is open
  if (menu.classList.contains('active')) {
    document.body.style.overflow = 'hidden';
  } else {
    document.body.style.overflow = '';
  }
}

function navigate(page, data) {
  if (page === 'favorites') {
    if (!state.currentUser) {
      openModal('authModal');
      return;
    }
    navigate('profile');
    setTimeout(() => {
      const tabs = document.querySelectorAll('.profile-tab');
      tabs.forEach(t => {
        if (t.textContent.toLowerCase().includes('saved') || t.textContent.toLowerCase().includes('favourite')) {
          t.click();
        }
      });
    }, 100);
    return;
  }

  if (page === 'profile-active') {
    if (!state.currentUser) {
      openModal('authModal');
      return;
    }
    navigate('profile');
    setTimeout(() => {
      const tabs = document.querySelectorAll('.profile-tab');
      tabs.forEach(t => {
        if (t.textContent.toLowerCase().includes('my ads') || t.textContent.toLowerCase().includes('active')) {
          t.click();
        }
      });
    }, 100);
    return;
  }

  const protectedPages = ['post', 'profile', 'favorites'];
  if (protectedPages.includes(page)) {
    if (!state.currentUser) {
      openModal('authModal');
      return;
    }
    if (state.currentUser.is_banned) {
      showToast("Access Denied: Your account is suspended.", "error");
      navigate('home');
      return;
    }
  }

  document.querySelectorAll('.page').forEach(p => p.classList.remove('active'));
  const el = document.getElementById('page-' + page);
  if (el) {
    el.classList.add('active');
    state.currentPage = page;
    window.location.hash = page; // Sync URL hash
    window.scrollTo(0, 0);

    // Toggle global back button visibility
    const backBtn = document.getElementById('globalBackButton');
    if (backBtn) {
      if (page === 'home') backBtn.classList.add('hidden');
      else backBtn.classList.remove('hidden');
    }
  }
  if (page === 'home') renderHome();
  if (page === 'search') renderSearchPage(data);
  if (page === 'detail' && data) renderDetailPage(data);
  if (page === 'post') renderPostPage();
  if (page === 'profile') renderProfilePage();
  if (page === 'seller') renderSellerPage();

  handleSearchVisibility();
}

/* ============================================================
   RENDER: HOME
============================================================ */
async function renderHome() {
  renderCategories();

  // Load from DB.listings (which now correctly holds local cache)
  let allListings = [...DB.listings];

  // Try to merge with cloud data if connected
  if (typeof sb !== 'undefined') {
    try {
      console.log("🌐 Fetching latest ads from Supabase...");
      const data = await fetchAdsFromSupabase();

      if (data && data.length > 0) {
        console.log(`✅ Received ${data.length} ads from cloud.`);
        allListings = data.map(l => ({
          id: String(l.id),
          user_id: l.user_id,
          title: l.title,
          price: l.price,
          category: l.category,
          sub_category: l.sub_category,
          condition: l.condition,
          description: l.description,
          seller: l.seller_name,
          phone: l.seller_phone,
          telegram: l.seller_telegram,
          photos: l.photos,
          specs: l.specs || {},
          featured: l.featured,
          sold: l.sold || false,
          time: new Date(l.created_at),
          views: l.views || 0,
          wishlist: DB.wishlist.includes(String(l.id))
        }));

        // Update local state and sync to storage
        DB.listings = allListings;
        saveListings();
        if (typeof globalUserAds !== 'undefined') globalUserAds = allListings;
      } else if (data && data.length === 0) {
        console.warn("⚠️ Cloud returned 0 ads. Keeping local cache if any.");
      }
    } catch (e) {
      console.error("❌ Cloud fetch failed:", e);
      showToast("Cloud sync error. Showing local ads.", "warning");
    }
  }

  const activeListings = allListings.filter(l => !l.sold);
  const featured = getSorted(activeListings.filter(l => l.featured), state.sortMode.featured);
  const recent = getSorted(activeListings, state.sortMode.recent);

  // Only show explicitly featured items in the slider (no fallback to recent)
  const sliderItems = featured;

  const fGrid = document.getElementById('featuredGrid');
  const rGrid = document.getElementById('recentGrid');
  const fCount = document.getElementById('featuredCount');
  const rCount = document.getElementById('recentCount');

  if (fGrid) {
    if (featured.length > 0) {
      fGrid.innerHTML = featured.map(l => renderListingCard(l)).join('');
    } else {
      fGrid.innerHTML = `<div style="grid-column: 1/-1; text-align: center; padding: 40px; color: var(--text-secondary);">
        <div style="font-size: 32px; margin-bottom: 12px;"></div>
        <p style="font-weight: 600;">No featured ads yet.</p>
      </div>`;
    }
  }

  if (rGrid) {
    if (recent.length > 0) {
      rGrid.innerHTML = recent.slice(0, 12).map(l => renderListingCard(l)).join('');
    } else {
      rGrid.innerHTML = `<div style="grid-column: 1/-1; text-align: center; padding: 40px; color: var(--text-secondary);">
        <div style="font-size: 32px; margin-bottom: 12px;"></div>
        <p style="font-weight: 600;">No listings found. Be the first to post!</p>
        <button class="btn-primary" onclick="navigate('post')" style="margin-top: 16px; padding: 10px 24px;">Post an Ad</button>
      </div>`;
    }
  }

  if (fCount) fCount.textContent = `${featured.length} featured ads`;
  if (rCount) rCount.textContent = `${recent.length} listings`;

  initSlider(sliderItems);
  renderPagination('homePagination', recent.length);
}

function renderCategories() {
  const grid = document.getElementById('categoriesGrid');
  if (!grid) return;
  grid.innerHTML = CATEGORIES.map(c => `
    <div class="cat-card" onclick="filterByCategory('${c.id}')">
      <div class="cat-icon">${c.icon}</div>
      <div class="cat-name">${c.name}</div>
      <div class="cat-count">${c.count.toLocaleString()} ads</div>
    </div>
  `).join('');
}


function getSpecsHtml(listing) {
  let specsHtml = '';
  if (listing.specs) {
    let items = [];
    let sp = {};
    try { sp = typeof listing.specs === 'string' ? JSON.parse(listing.specs) : listing.specs; } catch (e) { }

    if (listing.category === 'phones') {
      if (sp.brand) items.push(sp.brand);
      if (sp.ram) items.push(sp.ram.replace(/gb/i, '').trim() + 'GB RAM');
      if (sp.storage) items.push(sp.storage);
    } else if (listing.category === 'vehicles') {
      if (sp.make) items.push(sp.make);
      if (sp.year) items.push(sp.year);
    } else {
      if (sp.brand) items.push(sp.brand);
    }

    if (items.length > 0) {
      specsHtml = `<div style="display:flex; gap:4px; margin-bottom:8px; flex-wrap:wrap;">
        ${items.map(item => `<span style="background:var(--bg); border: 1px dashed var(--border); color:var(--text-secondary); font-size:10px; padding:3px 8px; border-radius:6px; font-weight:700; text-transform:uppercase;">${item}</span>`).join('')}
      </div>`;
    }
  }
  return specsHtml;
}

