// Helper to update seller card after async fetch
function updateSellerCardDetails(data) {
  const joinedDate = data.created_at ? new Date(data.created_at) : null;
  const joinedStr = joinedDate ? joinedDate.getFullYear() : '2023';

  const sellerId = data.id;
  const sellerName = data.name || data.full_name || data.seller_name;

  const activeCount = DB.listings.filter(l =>
    (l.user_id && String(l.user_id) === String(sellerId)) ||
    (l.seller === sellerName)
  ).filter(l => !l.sold).length;

  const joinedEl = document.getElementById('detailSellerJoinedText');
  if (joinedEl) joinedEl.textContent = joinedStr;

  const activityEl = document.getElementById('detailSellerActivity');
  if (activityEl) activityEl.textContent = `${activeCount} Total Ads Posted`;

  const isVerified = data.verification_status === 'verified' || data.is_verified;
  const verifEl = document.getElementById('detailSellerVerification');
  if (verifEl) {
    if (isVerified) {
      verifEl.textContent = '✓ Verified Seller';
      verifEl.style.color = '#166534';
    } else {
      verifEl.textContent = 'Unverified Account';
      verifEl.style.color = '#ef4444';
    }
  }

  const photoUrl = data.picture || data.avatar_url || data.photo_url;
  if (photoUrl) {
    const avatarContainer = document.getElementById('detailSellerAvatar');
    if (avatarContainer) {
      avatarContainer.innerHTML = `<img src="${photoUrl}" style="width:100%; height:100%; object-fit:cover; cursor:pointer;" onclick="showImageModal('${photoUrl}')">`;
      avatarContainer.style.background = 'none'; // Clear the initials background
    }
  }

  const similar = DB.listings.filter(l => l.id !== state.currentListing.id && l.category === state.currentListing.category && !l.sold).slice(0, 3);
  const simGrid = document.getElementById('similarGrid');
  if (simGrid) {
    simGrid.style.gridTemplateColumns = 'repeat(3, 1fr)';
    simGrid.innerHTML = similar.length > 0 ? similar.map(l => renderListingCard(l)).join('') : '<p class="text-muted" style="grid-column:1/-1;padding:16px">No similar listings found.</p>';
  }
}

function switchGalleryImg(src, el, index) {
  const mainImg = document.getElementById('galleryMainImg');
  if (mainImg) mainImg.src = src;

  if (typeof index !== 'undefined') {
    state.currentPhotoIndex = index;
    const photos = Array.isArray(state.currentListing.photos) ? state.currentListing.photos : [state.currentListing.photos || ''];
    const counter = document.getElementById('galleryCounter');
    if (counter) counter.textContent = `${index + 1} / ${photos.length}`;
  }

  const thumbs = document.querySelectorAll('#galleryThumbs img');
  if (thumbs.length) {
    thumbs.forEach(t => t.style.border = '1px solid #e2e8f0');
    if (thumbs[index]) thumbs[index].style.border = '2px solid var(--primary)';
  }
}

function nextGalleryPhoto() {
  const photos = Array.isArray(state.currentListing.photos) ? state.currentListing.photos : [state.currentListing.photos || ''];
  if (photos.length <= 1) return;

  state.currentPhotoIndex = (state.currentPhotoIndex + 1) % photos.length;
  const nextSrc = photos[state.currentPhotoIndex];

  const thumbs = document.querySelectorAll('.gallery-thumb');
  switchGalleryImg(nextSrc, thumbs[state.currentPhotoIndex], state.currentPhotoIndex);
}

function prevGalleryPhoto() {
  const photos = Array.isArray(state.currentListing.photos) ? state.currentListing.photos : [state.currentListing.photos || ''];
  if (photos.length <= 1) return;

  state.currentPhotoIndex = (state.currentPhotoIndex - 1 + photos.length) % photos.length;
  const prevSrc = photos[state.currentPhotoIndex];

  const thumbs = document.querySelectorAll('.gallery-thumb');
  switchGalleryImg(prevSrc, thumbs[state.currentPhotoIndex], state.currentPhotoIndex);
}


