/* ============================================================
   PAGINATION
============================================================ */
function renderPagination(containerId, total) {
  const container = document.getElementById(containerId);
  if (!container || total <= 12) { if (container) container.innerHTML = ''; return; }
  const pages = Math.ceil(total / 12);
  container.innerHTML = Array.from({ length: Math.min(pages, 5) }, (_, i) => `
    <button class="page-btn ${i === 0 ? 'active' : ''}" onclick="this.parentElement.querySelectorAll('.page-btn').forEach(b=>b.classList.remove('active')); this.classList.add('active')">${i + 1}</button>
  `).join('') + (pages > 5 ? `<button class="page-btn">…</button><button class="page-btn">${pages}</button>` : '');
}

/* ============================================================
   TOAST
============================================================ */
function showToast(msg, type = 'info') {
  const container = document.getElementById('toastContainer');
  const toast = document.createElement('div');
  toast.className = `toast ${type}`;
  // H-2 Fix: Use textContent to prevent XSS in toast messages
  const span = document.createElement('span');
  span.textContent = msg;
  toast.appendChild(span);
  container.appendChild(toast);
  setTimeout(() => {
    toast.style.animation = 'toastOut .3s ease forwards';
    setTimeout(() => toast.remove(), 300);
  }, 3000);
}

/* ============================================================
   HELPERS
============================================================ */
function formatPrice(price) {
  const n = Number(price);
  if (n >= 1000000) return 'ETB ' + (n / 1000000).toFixed(1) + 'M';
  if (n >= 1000) return 'ETB ' + n.toLocaleString();
  return 'ETB ' + n;
}

function getTimeAgo(date) {
  const d = new Date(date);
  const diff = (Date.now() - d) / 1000;
  if (diff < 60) return 'Just now';
  if (diff < 3600) return Math.floor(diff / 60) + 'm ago';
  if (diff < 86400) return Math.floor(diff / 3600) + 'h ago';
  if (diff < 604800) return Math.floor(diff / 86400) + 'd ago';
  return d.toLocaleDateString();
}

/* ============================================================
   GOOGLE AUTHENTICATION
============================================================ */
function initGoogleAuth() {
  // Check if running via file:// protocol
  if (window.location.protocol === 'file:') {
    console.warn("Google Auth will not work on file:// protocol. Use a local server (e.g., Live Server).");
    showToast("Google Login requires a local server (Live Server).", "warning");
  }

  if (typeof google === 'undefined') {
    setTimeout(initGoogleAuth, 500);
    return;
  }
  try {
    google.accounts.id.initialize({
      client_id: "527376856278-is7kgmdekhlom6rsrtvvuhc0qqf5pefv.apps.googleusercontent.com",
      callback: handleGoogleResponse,
      auto_select: false,
      cancel_on_tap_outside: false
    });
    // Render once in case it's already visible
    renderGoogleButton();
  } catch (err) {
    console.error("Google Auth Init Error:", err);
  }
}

function renderGoogleButton() {
  if (typeof google === 'undefined') return;
  const btnContainer = document.getElementById("googleBtnContainer");
  if (btnContainer) {
    try {
      google.accounts.id.renderButton(
        btnContainer,
        { theme: "outline", size: "large", width: "100%", text: "continue_with" }
      );
    } catch (e) {
      console.warn("Google Button Render Error:", e.message);
    }
  }
}

function openAuthModal(isSignup = false) {
  state.authIsSignup = isSignup;
  const title = document.getElementById('authModalTitle');
  const desc = document.getElementById('authModalDesc');
  const toggleText = document.getElementById('authToggleContainer');

  if (isSignup) {
    title.textContent = "Create Account";
    desc.textContent = "Join BUBU Gebeya today to start selling.";
    toggleText.innerHTML = `<p style="font-size:13px;">Already have an account? <a href="#" onclick="toggleAuthMode(false)" style="color:var(--primary); font-weight:700;">Sign In</a></p>`;
  } else {
    title.textContent = "Welcome Back";
    desc.textContent = "Sign in to manage your ads and bookmarks.";
    toggleText.innerHTML = `<p style="font-size:13px;">Don't have an account? <a href="#" onclick="toggleAuthMode(true)" style="color:var(--primary); font-weight:700;">Sign Up</a></p>`;
  }
  openModal('authModal');
}

function toggleAuthMode(isSignup) {
  openAuthModal(isSignup);
}

async function handleGoogleResponse(response) {
  const payload = decodeJwt(response.credential);
  if (payload) {
    const email = payload.email;
    const googleId = payload.sub;

    showToast("Checking cloud account...", "info");

    let profile = null;
    if (typeof sb !== 'undefined') {
      try {
        let { data, error } = await sb.from('profiles').select('*').eq('id', googleId).single();
        if (!data || error) {
          const { data: byEmail } = await sb.from('profiles').select('*').eq('email', email).single();
          data = byEmail;
        }
        profile = data;
      } catch (e) { console.warn("Profile fetch error:", e); }
    }

    // --- ENFORCE SIGN-IN VS SIGN-UP ---
    if (!state.authIsSignup && !profile) {
      // User clicked "Sign In" but we found NO account
      showToast("No account found. Please Sign Up first.", "warning");
      setTimeout(() => toggleAuthMode(true), 500);
      return;
    }

    if (profile?.is_banned) {
      showToast("Your account has been suspended by the administrator.", "error");
      return;
    }

    state.currentUser = {
      id: profile?.id || googleId,
      name: profile?.name || payload.name,
      email: email,
      picture: payload.picture,
      initials: (payload.given_name ? payload.given_name[0] : payload.name[0]),
      phone: profile?.phone || '',
      telegram: profile?.telegram || '',
      bio: profile?.bio || '',
      city: profile?.city || '',
      wishlist: profile?.wishlist || [],
      is_banned: profile?.is_banned || false,
      created_at: profile?.created_at || new Date().toISOString()
    };

    DB.wishlist = state.currentUser.wishlist || [];
    localStorage.setItem('bubu_active_session', JSON.stringify(state.currentUser));
    closeModal('authModal');

    if (!state.currentUser.phone || !state.currentUser.city) {
      if (document.getElementById('completeName')) document.getElementById('completeName').value = state.currentUser.name;
      openModal('completeProfileModal');
    } else {
      finalizeLogin();
    }
  }
}

async function finishCompleteProfile() {
  const name = document.getElementById('completeName').value.trim();
  const phone = document.getElementById('completePhone').value.trim();
  const city = document.getElementById('completeCity').value;

  if (!name) { showToast('Please enter your name', 'error'); return; }
  if (!phone || phone.length < 9) { showToast('Please enter a valid phone number', 'error'); return; }

  state.currentUser.name = name;
  state.currentUser.phone = phone;
  state.currentUser.city = city;
  state.currentUser.initials = name[0].toUpperCase();

  // Sync to Cloud
  if (typeof sb !== 'undefined') {
    try {
      await syncProfileToSupabase({
        id: state.currentUser.id,
        email: state.currentUser.email,
        name: state.currentUser.name,
        phone: state.currentUser.phone,
        city: state.currentUser.city,
        telegram: state.currentUser.telegram || '',
        bio: state.currentUser.bio || '',
        wishlist: state.currentUser.wishlist || []
      });
    } catch (e) {
      console.error("Cloud profile sync error:", e);
      showToast("Error saving to cloud, saved locally.", "warning");
    }
  }

  closeModal('completeProfileModal');
  finalizeLogin();
}

function guestLogin() {
  console.log("DEBUG: guestLogin triggered");
  const guestUser = {
    id: 'guest_' + Date.now(),
    email: 'guest@example.com',
    user_metadata: {
      full_name: 'Guest User',
      avatar_url: 'https://i.pravatar.cc/150?u=guest'
    }
  };

  persistUser(guestUser);
  updateAuthUI();
  closeModal('authModal');
  showToast("Welcome! You are now in Demo Mode.", "success");
}

function finalizeLogin() {
  updateAuthUI();
  localStorage.setItem('bubu_active_session', JSON.stringify(state.currentUser));
  showToast(`Welcome to BUBU Gebeya, ${state.currentUser.name}!`, 'success');

  if (state.currentPage === 'home') renderHome();
}

function persistUser(user) {
  const users = JSON.parse(localStorage.getItem('bubu_users') || '[]');
  const idx = users.findIndex(u => u.email === user.email);
  if (idx >= 0) users[idx] = user;
  else users.push(user);
  localStorage.setItem('bubu_users', JSON.stringify(users));
}

function loadStoredUser(email) {
  const users = JSON.parse(localStorage.getItem('bubu_users') || '[]');
  return users.find(u => u.email === email);
}

async function syncProfileToSupabase(data) {
  if (typeof sb === 'undefined') return;
  // Ensure the picture is always synced if it exists in state
  const pic = data.picture || (state.currentUser ? state.currentUser.picture : null);
  if (pic) {
    data.picture = pic;
    data.avatar_url = pic;
    data.photo_url = pic;
  }
  const { error } = await sb.from('profiles').upsert([data], { onConflict: 'id' });
  if (error) throw error;
}

function checkActiveSession() {
  const saved = localStorage.getItem('bubu_active_session');
  if (saved) {
    state.currentUser = JSON.parse(saved);
  }
}

function decodeJwt(token) {
  try {
    const base64Url = token.split('.')[1];
    const base64 = base64Url.replace(/-/g, '+').replace(/_/g, '/');
    const jsonPayload = decodeURIComponent(atob(base64).split('').map(function (c) {
      return '%' + ('00' + c.charCodeAt(0).toString(16)).slice(-2);
    }).join(''));
    return JSON.parse(jsonPayload);
  } catch (e) {
    console.error("JWT Decode Error", e);
    return null;
  }
}

function updateAuthUI() {
  const signInBtn = document.getElementById('signInBtn');
  const registerBtn = document.getElementById('registerBtn');
  const avatar = document.getElementById('authAvatar');

  if (state.currentUser) {
    // Hidden Login buttons
    if (signInBtn) signInBtn.classList.add('hidden');
    if (registerBtn) registerBtn.classList.add('hidden');

    // Show Avatar
    if (avatar) {
      avatar.classList.remove('hidden');
      const photoUrl = state.currentUser.picture || state.currentUser.avatar_url || state.currentUser.photo_url || state.currentUser.photo || state.currentUser.avatar;
      if (photoUrl) {
        avatar.innerHTML = `<img src="${photoUrl}" style="width:100%;height:100%;border-radius:50%;object-fit:cover;" onerror="this.parentElement.innerHTML='${state.currentUser.name?.[0] || '?'}'" />`;
      } else {
        const initials = state.currentUser.initials || state.currentUser.name?.split(' ').map(n => n[0]).join('').slice(0, 2).toUpperCase() || '?';
        avatar.textContent = initials;
      }
    }
  } else {
    // Show Login buttons
    if (signInBtn) signInBtn.classList.remove('hidden');
    if (registerBtn) registerBtn.classList.remove('hidden');

    // Hide Avatar
    if (avatar) avatar.classList.add('hidden');
  }
}

function handleProfileClick() {
  if (state.currentUser) {
    navigate('profile');
  } else {
    openModal('authModal');
  }
}

function logout() {
  openLogoutConfirm();
}

function openLogoutConfirm() {
  openModal('logoutConfirmOverlay');
}

async function confirmLogoutStep() {
  closeModal('logoutConfirmOverlay');

  if (typeof sb !== 'undefined') {
    await sb.auth.signOut();
  }
  localStorage.removeItem('bubu_user');
  localStorage.removeItem('bubu_active_session');
  state.currentUser = null;
  updateAuthUI();

  openModal('logoutSuccessOverlay');
}

/* ============================================================
   ACCOUNT DELETION
============================================================ */
function openDeleteAccountModal() {
  closeModal('editProfileModal');
  openModal('deleteAccountModal');
}

async function executeAccountDeletion() {
  if (!state.currentUser) return;
  const userId = state.currentUser.id;

  try {
    showToast('Cleaning up your data...', 'info');

    // 1. Delete all listings
    const { error: listingsError } = await sb
      .from('ads')
      .delete()
      .eq('user_id', userId);

    if (listingsError) throw listingsError;

    // 2. Delete profile
    const { error: profileError } = await sb
      .from('profiles')
      .delete()
      .eq('id', userId);

    if (profileError) throw profileError;

    // 3. Logout and Cleanup
    if (typeof sb !== 'undefined') {
      await sb.auth.signOut();
    }
    localStorage.removeItem('bubu_user');
    localStorage.removeItem('bubu_active_session');
    state.currentUser = null;

    closeModal('deleteAccountModal');
    showToast('Account and listings deleted successfully.', 'success');

    setTimeout(() => {
      navigate('home');
      window.location.reload();
    }, 2000);

  } catch (err) {
    console.error("Account deletion failed:", err);
    showToast('Failed to delete account. Please try again.', 'error');
  }
}


/* ============================================================
   PHONE REVEAL & SHARE
============================================================ */
function revealPhone(phone) {
  const btn = document.getElementById('showNumberBtn');
  if (!btn) return;

  // If already revealed, trigger the call
  if (btn.dataset.revealed === 'true') {
    window.location.href = `tel:${phone}`;
    return;
  }

  // First tap: reveal the number
  btn.dataset.revealed = 'true';
  btn.innerHTML = `
    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><path d="M22 16.92v3a2 2 0 0 1-2.18 2 19.79 19.79 0 0 1-8.63-3.07A19.5 19.5 0 0 1 4.69 13a19.79 19.79 0 0 1-3.07-8.67A2 2 0 0 1 3.6 2h3a2 2 0 0 1 2 1.72c.127.96.361 1.903.7 2.81a2 2 0 0 1-.45 2.11L7.91 9.91a16 16 0 0 0 6.16 6.16l1.17-1.17a2 2 0 0 1 2.11-.45c.907.339 1.85.573 2.81.7A2 2 0 0 1 22 16.92z"></path></svg>
    Call — ${phone}
  `;
  btn.style.letterSpacing = '0.5px';
}

function shareListing(id, title) {
  const url = `${location.origin}${location.pathname}?listing=${id}`;
  if (navigator.clipboard && navigator.clipboard.writeText) {
    navigator.clipboard.writeText(url).then(() => {
      showToast('Ad link copied to clipboard!', 'success');
    }).catch(() => {
      fallbackCopy(url);
    });
  } else {
    fallbackCopy(url);
  }
}

function fallbackCopy(text) {
  const ta = document.createElement('textarea');
  ta.value = text;
  ta.style.position = 'fixed';
  ta.style.opacity = '0';
  document.body.appendChild(ta);
  ta.select();
  document.execCommand('copy');
  document.body.removeChild(ta);
  showToast('Ad link copied to clipboard!', 'success');
}

/* ============================================================
   SEARCH HISTORY
============================================================ */
function saveSearchHistory(query) {
  let history = JSON.parse(localStorage.getItem('bubu_search_history') || '[]');
  history = [query, ...history.filter(q => q.toLowerCase() !== query.toLowerCase())].slice(0, 5);
  localStorage.setItem('bubu_search_history', JSON.stringify(history));
}

function showRecentSearches() {
  const input = document.getElementById('heroSearch');
  const dropdown = document.getElementById('recentSearchesDropdown');
  if (!dropdown) return;

  let history = JSON.parse(localStorage.getItem('bubu_search_history') || '[]');
  const currentVal = (input?.value || '').toLowerCase().trim();
  if (currentVal) {
    history = history.filter(q => q.toLowerCase().includes(currentVal));
  }
  if (history.length === 0) { dropdown.style.display = 'none'; return; }

  dropdown.innerHTML = `
    <div style="display:flex; justify-content:space-between; align-items:center; padding:4px 8px 8px; border-bottom:1px solid var(--border); margin-bottom:4px;">
      <span style="font-size:11px; font-weight:700; color:var(--text-muted); text-transform:uppercase; letter-spacing:.5px;">Recent</span>
      <button onclick="clearSearchHistory()" style="font-size:11px; color:var(--primary); font-weight:700; background:none; border:none; cursor:pointer; padding:0;">Clear</button>
    </div>
    ${history.map(q => `
      <div onclick="runHistorySearch('${q.replace(/'/g, "\\'")}')"
        style="display:flex; align-items:center; gap:10px; padding:9px 10px; border-radius:10px; cursor:pointer; transition:background .15s;"
        onmouseover="this.style.background='var(--bg)'" onmouseout="this.style.background='none'">
        <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="var(--text-muted)" stroke-width="2.5" stroke-linecap="round"><circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/></svg>
        <span style="font-size:14px; color:var(--text-primary);">${q}</span>
      </div>`).join('')}
  `;
  dropdown.style.display = 'block';
}

function hideRecentSearches() {
  const d = document.getElementById('recentSearchesDropdown');
  if (d) d.style.display = 'none';
}

function runHistorySearch(query) {
  const input = document.getElementById('heroSearch');
  if (input) input.value = query;
  state.searchQuery = query;
  hideRecentSearches();
  navigate('search', { query });
}

function clearSearchHistory() {
  localStorage.removeItem('bubu_search_history');
  hideRecentSearches();
}

/* ============================================================
   IMAGE ZOOM (double-click + pinch-to-zoom)
============================================================ */
(function initGalleryZoom() {
  let _zoomed = false;
  let _lastTap = 0;
  let _pinchStartDist = 0;
  let _currentScale = 1;

  window.toggleImageZoom = function (e) {
    const img = document.getElementById('galleryMainImg');
    const wrap = document.getElementById('galleryZoomWrap');
    if (!img || !wrap) return;
    _zoomed = !_zoomed;
    if (_zoomed) {
      // Zoom in to click point
      const rect = wrap.getBoundingClientRect();
      const ox = ((e.clientX - rect.left) / rect.width * 100).toFixed(1);
      const oy = ((e.clientY - rect.top) / rect.height * 100).toFixed(1);
      img.style.transformOrigin = `${ox}% ${oy}%`;
      img.style.transform = 'scale(2.2)';
      img.style.cursor = 'zoom-out';
      wrap.style.cursor = 'zoom-out';
      _currentScale = 2.2;
    } else {
      img.style.transform = 'scale(1)';
      img.style.cursor = 'zoom-in';
      wrap.style.cursor = 'zoom-in';
      _currentScale = 1;
    }
  };

  // Reset zoom when switching images
  const origSwitch = window.switchGalleryImg;
  window.switchGalleryImg = function (src, el, index) {
    const img = document.getElementById('galleryMainImg');
    if (img) { img.style.transform = 'scale(1)'; img.style.cursor = 'zoom-in'; }
    const wrap = document.getElementById('galleryZoomWrap');
    if (wrap) wrap.style.cursor = 'zoom-in';
    _zoomed = false; _currentScale = 1;
    if (origSwitch) origSwitch(src, el, index);
  };

  // Pinch-to-zoom (touch devices)
  document.addEventListener('touchstart', e => {
    if (!document.getElementById('galleryZoomWrap')) return;
    if (e.touches.length === 2) {
      const dx = e.touches[0].clientX - e.touches[1].clientX;
      const dy = e.touches[0].clientY - e.touches[1].clientY;
      _pinchStartDist = Math.hypot(dx, dy);
    }
    // Double-tap detection
    if (e.touches.length === 1) {
      const now = Date.now();
      if (now - _lastTap < 300) {
        const img = document.getElementById('galleryMainImg');
        if (img && e.target === img) {
          toggleImageZoom({ clientX: e.touches[0].clientX, clientY: e.touches[0].clientY });
        }
      }
      _lastTap = now;
    }
  }, { passive: true });

  document.addEventListener('touchmove', e => {
    const img = document.getElementById('galleryMainImg');
    if (!img || e.touches.length !== 2) return;
    const dx = e.touches[0].clientX - e.touches[1].clientX;
    const dy = e.touches[0].clientY - e.touches[1].clientY;
    const dist = Math.hypot(dx, dy);
    const ratio = dist / (_pinchStartDist || dist);
    const newScale = Math.min(4, Math.max(1, _currentScale * ratio));
    img.style.transform = `scale(${newScale})`;
    img.style.transformOrigin = 'center';
  }, { passive: true });

  document.addEventListener('touchend', e => {
    const img = document.getElementById('galleryMainImg');
    if (!img) return;
    const match = img.style.transform.match(/scale\(([^)]+)\)/);
    if (match) _currentScale = parseFloat(match[1]);
    if (_currentScale <= 1.05) {
      img.style.transform = 'scale(1)';
      _currentScale = 1; _zoomed = false;
    }
  }, { passive: true });
})();

/* ============================================================
   MARK AS SOLD / MOVE TO TOP
============================================================ */
async function markAsSold(id, currentlySold) {
  const newStatus = !currentlySold;
  if (typeof sb !== 'undefined') {
    try {
      const { error } = await sb.from('ads').update({ sold: newStatus }).eq('id', String(id));
      if (error) throw error;
    } catch (e) {
      showToast('Could not update — check connection', 'error');
      return;
    }
  }
  // Update local DB
  const l = DB.listings.find(x => String(x.id) === String(id));
  if (l) l.sold = newStatus;
  showToast(newStatus ? 'Listing marked as Sold' : 'Listing reactivated', 'success');

  // Switch to the correct profile tab and update its highlight
  const targetTab = newStatus ? 'sold' : 'active';
  const tabEls = document.querySelectorAll('.profile-tab');
  tabEls.forEach(t => {
    t.classList.remove('active');
    const tabId = t.getAttribute('onclick')?.match(/'([^']+)'/)?.[1];
    if (tabId === targetTab) t.classList.add('active');
  });
  renderUserListings(targetTab);
}

async function moveToTop(id) {
  const now = new Date().toISOString();
  if (typeof sb !== 'undefined') {
    try {
      const { error } = await sb.from('ads').update({ created_at: now }).eq('id', String(id));
      if (error) throw error;
    } catch (e) {
      showToast('Could not refresh — check connection', 'error');
      return;
    }
  }
  // Update local cache time
  const l = DB.listings.find(x => String(x.id) === String(id));
  if (l) l.time = new Date(now);
  showToast('Listing moved to top!', 'success');
  renderUserListings('active');
}

/* ============================================================
   IMAGE VIEWER
============================================================ */
function showImageModal(src) {
  const overlay = document.createElement('div');
  overlay.style.position = 'fixed';
  overlay.style.top = '0';
  overlay.style.left = '0';
  overlay.style.width = '100vw';
  overlay.style.height = '100vh';
  overlay.style.backgroundColor = 'rgba(0,0,0,0.95)';
  overlay.style.backdropFilter = 'blur(10px)';
  overlay.style.zIndex = '9999999';
  overlay.style.display = 'flex';
  overlay.style.alignItems = 'center';
  overlay.style.justifyContent = 'center';
  overlay.style.cursor = 'zoom-out';
  overlay.style.padding = '10px';
  overlay.onclick = () => document.body.removeChild(overlay);

  const img = document.createElement('img');
  img.src = src;
  // Ensure the image is as large as possible without overflowing
  img.style.maxWidth = '95%';
  img.style.maxHeight = '95%';
  img.style.width = 'auto';
  img.style.height = 'auto';
  // If the image is very small, we still want it to appear reasonably large
  img.style.minWidth = '320px';
  img.style.borderRadius = '12px';
  img.style.boxShadow = '0 30px 60px rgba(0,0,0,0.7)';
  img.style.objectFit = 'contain';

  overlay.appendChild(img);
  document.body.appendChild(overlay);
}

/* ============================================================
   SYSTEM BROADCAST & MAINTENANCE
============================================================ */
async function checkSystemBroadcast() {
  if (typeof sb === 'undefined') return;

  try {
    const { data, error } = await sb.from('system_config').select('*');
    if (error) throw error;

    const maintenanceMode = data.find(i => i.key === 'maintenance_mode')?.value === 'true';
    const systemMsg = data.find(i => i.key === 'broadcast_message')?.value || "";

    const overlay = document.getElementById('maintenanceOverlay');
    const msgEl = document.getElementById('maintenanceMsg');

    // 1. Maintenance Mode
    if (maintenanceMode) {
      if (overlay) {
        msgEl.textContent = systemMsg || "System Update in progress";
        overlay.style.display = 'flex';
        document.body.style.overflow = 'hidden';
      }
      return;
    } else {
      if (overlay) {
        overlay.style.display = 'none';
        document.body.style.overflow = '';
      }
    }

    // 2. Broadcast Message (Modal)
    if (systemMsg.trim() !== '') {
      const modal = document.getElementById('broadcastModal');
      const modalMsgEl = document.getElementById('broadcastDisplayMsg');
      if (modal && modalMsgEl) {
        modalMsgEl.textContent = systemMsg;
        modal.style.display = 'flex';
      }
    }
  } catch (err) {
    console.error("Broadcast Check Error:", err);
  }
}

function closeBroadcastModal() {
  const modal = document.getElementById('broadcastModal');
  if (modal) modal.style.display = 'none';
}
function handleSearchVisibility() {
  const headerSearch = document.getElementById('headerSearchContainer');
  if (!headerSearch) return;

  if (state.currentPage === 'home') {
    const heroSearch = document.getElementById('heroSearch');
    if (heroSearch && window.getComputedStyle(heroSearch).display !== 'none') {
      const heroRect = heroSearch.getBoundingClientRect();
      // On desktop, we want to show the top nav search as soon as the hero search starts leaving the view
      const threshold = window.innerWidth <= 768 ? 10 : 80;
      if (heroRect.bottom < threshold) {
        headerSearch.classList.add('visible');
      } else {
        headerSearch.classList.remove('visible');
      }
    } else {
      headerSearch.classList.add('visible');
    }
  } else {
    headerSearch.classList.add('visible');
  }
}

/* ============================================================
   SMART SEARCH & SUGGESTIONS
============================================================ */
function normalizeSearchText(text) {
  if (!text) return '';
  return text.toLowerCase().replace(/\s+/g, '');
}

function handleSearchInput(event, context) {
  const query = event.target.value;
  if (event.key === 'Enter') {
    performSearch(context);
    return;
  }
  renderSearchSuggestions(query, context);
}

function renderSearchSuggestions(query, context) {
  const suggestionsDiv = document.getElementById('searchSuggestions');
  if (!suggestionsDiv) return;

  if (!query || query.length < 2) {
    suggestionsDiv.classList.add('hidden');
    return;
  }

  const normalizedQuery = normalizeSearchText(query);
  const matches = DB.listings
    .filter(l => !l.sold)
    .filter(l => normalizeSearchText(l.title).includes(normalizedQuery))
    .slice(0, 6);

  if (matches.length === 0) {
    suggestionsDiv.classList.add('hidden');
    return;
  }

  suggestionsDiv.innerHTML = matches.map(l => `
    <div class="search-suggestion-item" onclick="selectSuggestion('${l.id}')">
      <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="11" cy="11" r="8"></circle><path d="m21 21-4.35-4.35"></path></svg>
      <span>${l.title}</span>
    </div>
  `).join('');
  suggestionsDiv.classList.remove('hidden');
}

function selectSuggestion(id) {
  const suggestionsDiv = document.getElementById('searchSuggestions');
  if (suggestionsDiv) suggestionsDiv.classList.add('hidden');
  openListing(id);
}

function performSearch(context) {
  const inputId = context === 'hero' ? 'heroSearch' : 'navSearch';
  const query = document.getElementById(inputId)?.value || '';

  const suggestionsDiv = document.getElementById('searchSuggestions');
  if (suggestionsDiv) suggestionsDiv.classList.add('hidden');

  state.searchQuery = query;
  if (query.trim()) saveSearchHistory(query.trim());
  navigate('search', { query: query });
}


/* ============================================================
   INIT
============================================================ */
document.addEventListener('DOMContentLoaded', () => {
  initDB();
  checkActiveSession();
  checkSystemBroadcast(); // Initial check

  // REAL-TIME BROADCAST LISTENER
  if (typeof sb !== 'undefined') {
    sb.channel('system_configs')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'system_config' }, () => {
        console.log("System config updated, re-checking broadcast...");
        checkSystemBroadcast();
      })
      .subscribe();
  }

  window.addEventListener('scroll', handleSearchVisibility);
  handleSearchVisibility();


  // Deep-link: ?listing=ID → open that product directly
  const urlParams = new URLSearchParams(window.location.search);
  const deepListingId = urlParams.get('listing');
  if (deepListingId) {
    renderHome(); // render home first so DB is populated
    // Give DB time to load from Supabase, then open
    const tryOpen = (attempts = 0) => {
      const found = DB.listings.find(l => String(l.id) === String(deepListingId));
      if (found) {
        navigate('detail', found);
      } else if (attempts < 10) {
        setTimeout(() => tryOpen(attempts + 1), 400);
      } else {
        // Fallback: fetch directly from Supabase
        if (typeof sb !== 'undefined') {
          sb.from('ads').select('*').eq('id', deepListingId).single().then(({ data }) => {
            if (data) {
              const l = {
                id: String(data.id), title: data.title, price: data.price,
                category: data.category, condition: data.condition,
                description: data.description, seller: data.seller_name,
                phone: data.seller_phone, telegram: data.seller_telegram,
                photos: data.photos, specs: data.specs || {},
                featured: data.featured, time: new Date(data.created_at),
                views: data.views, user_id: data.user_id
              };
              navigate('detail', l);
            } else {
              renderHome();
            }
          });
        } else {
          renderHome();
        }
      }
    };
    setTimeout(() => tryOpen(), 300);
  } else {
    const initialPage = window.location.hash.replace('#', '') || 'home';
    if (initialPage === 'home') {
      renderHome();
    } else {
      navigate(initialPage);
    }
  }

  initGoogleAuth();
  updateAuthUI();
  startSafetyWarnings();

  window.addEventListener('hashchange', () => {
    const page = window.location.hash.replace('#', '') || 'home';
    if (state.currentPage !== page) {
      navigate(page);
    }
  });

  // Load Lottie Icons
  if (typeof lottie !== 'undefined' || customElements.get('lottie-player')) {
    const initLottie = () => {
      document.querySelectorAll('.logo-lottie').forEach(el => {
        if (typeof el.load === 'function') el.load(CART_LOGO_JSON);
      });
    };

    if (customElements.get('lottie-player')) {
      initLottie();
    } else {
      customElements.whenDefined('lottie-player').then(initLottie);
    }
  }
});


